INSERT INTO stock_book (item_id, transaction_type, inward_qty, outward_qty, balance_qty, remarks, created_by) SELECT i.id, 'INWARD', i.quantity, 0, i.quantity, 'Imported opening stock from workbook dated 08.07.2025', 1 FROM items i WHERE i.deleted_at IS NULL AND i.item_code REGEXP '^(PRINT|STAT|HOUSE|POOJA)-' AND NOT EXISTS (SELECT 1 FROM stock_book sb WHERE sb.item_id=i.id AND sb.remarks='Imported opening stock from workbook dated 08.07.2025');
INSERT INTO activity_logs (user_id, action, ip_address) VALUES (1, 'Imported stationary and printing workbook items; old sample item master archived', 'localhost');
